// ════════════════════════════════════════════
// ① 修改頻道清單（用 YouTube URL 格式）
// ② 修改 AI_PROVIDER：'claude' / 'gemini' / 'openai'
// ════════════════════════════════════════════

const AI_PROVIDER = 'claude';  // ← 在這裡切換 AI

const CHANNELS = [
  { name: '頻道A', url: 'https://www.youtube.com/@channelA' },
  { name: '頻道B', url: 'https://www.youtube.com/@channelB' },
  { name: '頻道C', url: 'https://www.youtube.com/channel/UCxxxxxxxxxxxxxxxxxx' },
  { name: '頻道D', url: 'https://www.youtube.com/@channelD' },
  { name: '頻道E', url: 'https://www.youtube.com/@channelE' },
];

return CHANNELS.map(ch => ({ json: { ...ch, aiProvider: AI_PROVIDER } }));

// 從 YouTube 頁面 HTML 解析 channelId
const html = $input.first().json.data || '';
const channelData = $('頻道設定 & AI選擇').first().json;

const match = html.match(/"channelId":"(UC[\w-]{22})"/) 
           || html.match(/"externalId":"(UC[\w-]{22})"/);

if (!match) {
  // 如果是 /channel/UCxxxx 格式，直接從 URL 取
  const urlMatch = channelData.url.match(/\/channel\/(UC[\w-]{22})/);
  if (urlMatch) {
    return [{ json: { ...channelData, channelId: urlMatch[1] } }];
  }
  // 找不到就跳過
  return [];
}

return [{ json: { ...channelData, channelId: match[1] } }];

// 解析 RSS，取最新 3 支（1天內）
const xml = $input.first().json.data || '';
const meta = $('解析 Channel ID').first().json;

const cutoff = Date.now() - 24 * 60 * 60 * 1000;
const entries = [];
const re = /<entry>([\s\S]*?)<\/entry>/g;
let m;

while ((m = re.exec(xml)) !== null && entries.length < 3) {
  const b = m[1];
  const published = new Date((b.match(/<published>([^<]+)<\/published>/) || [])[1] || 0);
  if (published.getTime() < cutoff) continue;

  const videoId = (b.match(/<yt:videoId>([^<]+)<\/yt:videoId>/) || [])[1] || '';
  const title   = ((b.match(/<title>([^<]+)<\/title>/) || [])[1] || '')
                    .replace(/&amp;/g,'&').replace(/&lt;/g,'<').replace(/&gt;/g,'>');
  const desc    = ((b.match(/<media:description>([\s\S]*?)<\/media:description>/) || [])[1] || '')
                    .replace(/<[^>]+>/g, '').trim().slice(0, 800);

  if (!videoId) continue;
  entries.push({
    channelName: meta.name,
    channelUrl:  meta.url,
    aiProvider:  meta.aiProvider,
    videoId,
    title,
    url:         `https://www.youtube.com/watch?v=${videoId}`,
    published:   published.toISOString().slice(0, 10),
    description: desc,
  });
}

if (!entries.length) return [];
return entries.map(e => ({ json: e }));

// 統一解析三個 AI 的回傳格式
const raw = (() => {
  const data = $input.first().json;
  // Claude
  if (data.content?.[0]?.text) return data.content[0].text;
  // Gemini
  if (data.candidates?.[0]?.content?.parts?.[0]?.text)
    return data.candidates[0].content.parts[0].text;
  // OpenAI
  if (data.choices?.[0]?.message?.content)
    return data.choices[0].message.content;
  return '';
})().trim();

let summary = '', bullets = '';
if (raw.includes('一句摘要：')) {
  const lines = raw.split('\n');
  let inBullets = false;
  const bl = [];
  for (const line of lines) {
    const t = line.trim();
    if (t.startsWith('一句摘要：')) summary = t.replace('一句摘要：','').trim();
    else if (t.startsWith('重點條列：')) inBullets = true;
    else if (inBullets && t.startsWith('•')) bl.push(t);
  }
  bullets = bl.join('\n');
} else {
  summary = raw.slice(0, 100);
}

// 取得原始影片資料（從路由前的節點）
const video = $('過濾空結果').first().json;
const tw = new Date().toLocaleString('zh-TW', { timeZone: 'Asia/Taipei', hour12: false });

return [{ json: {
  channel:    video.channelName,
  title:      video.title,
  date:       video.published,
  url:        video.url,
  summary,
  bullets,
  aiSource:   video.aiProvider.toUpperCase(),
  analyzedAt: tw,
} }];
